SELECT user_id, COUNT(*) AS total_interactions
FROM interactions
GROUP BY user_id;

SELECT object_shared_type, COUNT(*) AS total_shared_content
FROM shared_content
GROUP BY object_shared_type;

SELECT users.id, users.username, reviewers.role
FROM users
JOIN reviewers ON users.id = reviewers.user_id;

SELECT id 
FROM shared_content 
WHERE status_code = (SELECT MAX(status_code) FROM shared_content);

SELECT COUNT(*)
FROM shared_content
WHERE deleted_at IS NULL AND status_code <> 2;

SELECT MAX(value) AS max_interactions
FROM analytics
WHERE metric = 'interactions';

SELECT SUM(file_size)
FROM objects
WHERE file_format = 'jpg';

SELECT u.username, u.email
FROM users u
JOIN content_creators cc ON u.id = cc.user_id;

SELECT users.id, users.username, reviewers.role
FROM users
JOIN reviewers ON users.id = reviewers.user_id;
